public partial class BaseTest
{
        public void testIsJsonEncodedObject()
        {
            var exchange = new ccxt.Exchange(new Dictionary<string, object>() {
                { "id", "sampleexchange" },
            });
            Assert(exchange.isJsonEncodedObject("{\"key\":\"value\"}"));
            Assert(exchange.isJsonEncodedObject("{}"));
            Assert(exchange.isJsonEncodedObject("[]"));
            // todo: the belows  are not ideal, but currently valid
            Assert(exchange.isJsonEncodedObject("{x"));
            Assert(exchange.isJsonEncodedObject("[x"));
            Assert(exchange.isJsonEncodedObject("{"));
            Assert(exchange.isJsonEncodedObject("["));
            // invalid
            Assert(!isTrue(exchange.isJsonEncodedObject("x")));
            Assert(!isTrue(exchange.isJsonEncodedObject("")));
            Assert(!isTrue(exchange.isJsonEncodedObject("}")));
            Assert(!isTrue(exchange.isJsonEncodedObject("]")));
            Assert(!isTrue(exchange.isJsonEncodedObject("null")));
            Assert(!isTrue(exchange.isJsonEncodedObject("undefined")));
        }
}